import React from 'react';
import '../App.css';

const Hero = () => {

  const sliderData = [
  {
    title: "Fast Food Restaurant",
    description: "Doloremque, itaque aperiam facilis rerum, commodi, temporibus sapiente ad mollitia laborum quam quisquam esse error unde.",
    image: "/image/hero-bg.jpg" // Slide 1 Image
  },
  {
    title: "Delicious Pizza",
    description: "Veniam debitis quaerat officiis quasi cupiditate quo, nihil gubergren, eos natus lead architecto.",
    image: "/image/pizza-slide.png" // Replace with your 2nd image
  },
  {
    title: "Tasty Pasta",
    description: "Explicabo esse amet tempora quibusdam laudantium, ratione eaque omnis id delectus ducimus.",
    image: "/image/pasta-slide.png" // Replace with your 3rd image
  }
];

  const [current, setCurrent] = useState(0);

  // Auto-move slider every 5 seconds
  useEffect(() => {
    const next = (current + 1) % sliderData.length;
    const id = setTimeout(() => setCurrent(next), 5000);
    return () => clearTimeout(id);
  }, [current]);

  return (
    <div className="hero_area">
      {/* Background Container for the image texture */}
      <div className="bg-box">
        <img src="/image/hero-bg.jpg" alt="" />
      </div>

      <header className="header_section">
        <div className="container">
          <nav className="navbar">
            <a className="navbar-brand" href="/">
              <span>Feane</span>
            </a>
            <div className="nav_container">
              <ul className="nav_links">
                <li className="active"><a href="/">HOME</a></li>
                <li><a href="/menu">MENU</a></li>
                <li><a href="/about">ABOUT</a></li>
                <li><a href="/book">BOOK TABLE</a></li>
              </ul>
              <div className="user_option">
                <a href=""><i className="fa fa-user" aria-hidden="true"></i></a>
                <a href=""><i className="fa fa-shopping-cart" aria-hidden="true"></i></a>
                <form className="form-inline">
                  <button className="btn nav_search-btn" type="submit">
                    <i className="fa fa-search" aria-hidden="true"></i>
                  </button>
                </form>
                <a href="" className="order_online">Order Online</a>
              </div>
            </div>
          </nav>
        </div>
      </header>

      <section className="slider_section">
        <div className="container">
          <div className="row">
            <div className="detail-box">
              <h1>Fast Food Restaurant</h1>
              <p>
                Doloremque, itaque aperiam facilis rerum, commodi, temporibus sapiente ad mollitia laborum quam quisquam esse error unde. Tempora ex doloremque, labore, sunt repellat dolore, iste magni quos nihil ducimus libero ipsam.
              </p>
              <div className="btn-box">
                <a href="" className="btn1">Order Now</a>
              </div>
            </div>
            
          </div>
          
          <div className="slider_indicators">
            <span className="dot"></span>
            <span className="dot active-dot"></span>
            <span className="dot"></span>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Hero;
